mapper.sql:
where s.status = 'ACTIVE'
  and s.source_type != 'SIDE_QUESTION'
  and (
    s.created_by_user_id = #{userId}
    or exists (
        select 1
        from runs r
        where r.session_id = s.session_id
          and r.triggered_by_user_id = #{userId}
    )
    or exists (
        select 1
        from session_messages sm
        where sm.session_id = s.session_id
          and sm.sender_user_id = #{userId}
    )
  )

  and (
    lower(s.title) like #{queryPattern}
    or lower(s.session_id) like #{queryPattern}
  )

mapper.select:
select



order by s.updated_at desc, s.id desc
limit #{limit} offset #{offset}
